 switch (ret) {
 case HTTP_UPDATE_FAILED:
 Serial.printf("HTTP_UPDATE_FAILED Error (%d): %s\n", ESPhttpUpdate.getLastError(), ESPhttpUpdate.getLastErrorString().c_str());
 break;

 case HTTP_UPDATE_NO_UPDATES:
 Serial.println("HTTP_UPDATE_NO_UPDATES");
 break;

 case HTTP_UPDATE_OK:
 Serial.println("HTTP_UPDATE_OK");
 break;
 }

 return ret;
}

void Zevice::autoConnect() {
 int n;
 do {
 n = WiFi.scanNetworks();
 } while (n < 1);

 int networks[n];
 for (int i = 0; i < n; i++) {
 networks[i] = WiFi.RSSI(i);
 }

 int maxSignal = 0,
 maxSignalKnown = 0,
 networksCount = sizeof(ssid) / sizeof(ssid[0]),
 known;

 for (int i = 0; i < n; i++) {
 known = 0;
 for (int j = 0; j < networksCount; j++) {
 if (WiFi.SSID(i) == ssid[j]) {
 known = j;
 }
 }
 if (networks[i] > networks[maxSignal]) {
 maxSignal = i;
 maxSignalKnown = known;
 }
 }

 if (knowsNetwork(WiFi.SSID(maxSignalKnown))) {
 Serial.println(ssid[maxSignalKnown]);
 Serial.println(password[maxSignalKnown]);
 WiFi.begin(ssid[maxSignalKnown], password[maxSignalKnown]);
// WiFiManager wifiManager;
// wifiManager.resetSettings();
// wifiManager.autoConnect(ssid, password);
 int i = 0;
 while (WiFi.status() != WL_CONNECTED) { // Wait for the Wi-Fi to connect
 delay(1000);
 Serial.print(++i); Serial.print(' ');
 Serial.print("IP address:\t");
 Serial.println(WiFi.localIP());
 }
 webserver->begin();
 webserver->on("/zevice/update", [this]() {
 t_httpUpdate_return ret = this->checkUpdates();
 this->webserver->send(200, "text/html", String(ret) + "<br/><br/> No updates<br/><a href='/'>Home</a>");
 });
 webserver->on("/zevice/upload", [this]() {
 this->webserver->sendHeader("Connection", "close");
 this->webserver->send(200, "text/html", uploadForm);
 });
 webserver->on("/zevice/upload_update", HTTP_POST, [this]() {
 this->webserver->sendHeader("Connection", "close");
 this->webserver->send(200, "text/plain", (Update.hasError()) ? "FAIL" : "SUCCESS. REBOOTING...");
 delay(1000);
 ESP.restart();
 }, [this]() {
 // Handle the actual file upload chunk by chunk
 HTTPUpload& upload = this->webserver->upload();
 if (upload.status == UPLOAD_FILE_START) {
 Serial.printf("Update started: %s\n", upload.filename.c_str());
 if (!Update.begin(OTA_SIZE_ARG)) { // start with max available size
 Update.printError(Serial);
 }
 } else if (upload.status == UPLOAD_FILE_WRITE) {
 if (Update.write(upload.buf, upload.currentSize) != upload.currentSize) {
 Update.printError(Serial);
 }
 } else if (upload.status == UPLOAD_FILE_END) {
 if (Update.end(true)) { // true to set the size to the current progress
 Serial.printf("Update Success: %u bytes\nRebooting...\n", upload.totalSize);
 } else {
 Update.printError(Serial);
 }
 }
 });
 } else {
 Serial.println("No known networks");
 }
}
