Client QUIC endpoint
use anyhow::Error;
use quinn::{ClientConfig, Endpoint, MtuDiscoveryConfig, TransportConfig, congestion::BbrConfig};
use rustls::pki_types::CertificateDer;

use std::sync::Arc;

use crate::config::QuicConfig;

pub fn make_client_endpoint(config: &QuicConfig) -> Result<Endpoint, Error> {
 let mut client_cfg = configure_client(config)?;
 client_cfg.transport_config(Arc::new(build_transport_config(config)));
 let mut endpoint = Endpoint::client(config.endpoint_address)?;
 endpoint.set_default_client_config(client_cfg);
 Ok(endpoint)
}

fn configure_client(config: &QuicConfig) -> Result<ClientConfig, Error> {
 // читаем сертификат с диска
 let cert_bytes = std::fs::read(&config.server_cert)?;
 let server_cert = CertificateDer::from(cert_bytes);
 let mut certs = rustls::RootCertStore::empty();
 certs.add(server_cert)?;
 Ok(ClientConfig::with_root_certificates(Arc::new(certs))?)
}

fn build_transport_config(quic_config: &QuicConfig) -> TransportConfig {
 let mut transport = TransportConfig::default();

 transport.mtu_discovery_config(Some(MtuDiscoveryConfig::default()));
 transport.datagram_receive_buffer_size(Some(quic_config.receive_buffer_size_kb * 1024));
 transport.datagram_send_buffer_size(quic_config.send_buffer_size_kb * 1024);
 transport.max_concurrent_uni_streams(0u32.into());
 transport.max_concurrent_bidi_streams(10u32.into());
 transport.congestion_controller_factory(Arc::new(BbrConfig::default()));

 transport
}
В основном цикле просто подключаемся к серверу и запускаем туннель
tokio::spawn(async move {
 loop {
 let connecting = match endpoint.connect(server_address, &server_name) {
 Ok(c) => c,
 Err(e) => {
 error!("connect failed: {e:#}, retrying in {backoff:?}");
 sleep(backoff).await;
 continue;
 }
 };
 let connection = match connecting.await {
 Ok(c) => c,
 Err(e) => {
 error!("handshake failed: {e:#}, retrying in {backoff:?}");
 sleep(backoff).await;
 continue;
 }
 };
 info!("connected to server {}", connection.remote_address());
 match run_tunnel(connection.clone(), &config).await {
 Ok(_) => error!("session ended, reconnecting..."),
 Err(e) => error!("error running tunnel: {e:#}"),
 };
 connection.close(CLOSE_CODE_NORMAL, &[]);
 sleep(backoff).await;
 }
})
Обмен трафиком начинается с handshake: клиент отправляет свои credentials, сервер проверяет их и в случае успеха назначает IP адрес
pub struct ClientHello {
 pub user: String,
 pub secret: String,
}

pub struct ServerHello {
 pub addr: Ipv4Addr,
 pub prefix: u8,
}

async fn handshake(
 connection: &Connection,
 config: &VpnConfig,
) -> Result<ServerHello, anyhow::Error> {
 // QUIC stream, чтобы не терять трафик
 let (mut send, mut recv) = connection.open_bi().await?;
 // отправляем данные для аутентификации
 let client_hello_bytes: Vec<u8> = ClientHello {
 user: config.user.name.clone(),
 secret: config.user.secret.clone(),
 }
 .into();
 info!("sending client hello");
 send.write_all(&client_hello_bytes).await?;
 send.finish()?;

 let server_hello_bytes = recv.read_to_end(MAX_HANDSHAKE_DATA).await?;
 let server_hello = ServerHello::from(server_hello_bytes);
 info!("authentication succeeded");
 // получили адрес для TUN
 Ok(server_hello)
}
После handshake создаем TUN интерфейс, настраиваем маршрутизацию
pub async fn run_tunnel(connection: Connection, config: &VpnConfig) -> Result<()> {
 let handshake = handshake(&connection, config).await?;

 let addr: Ipv4Addr = handshake.addr;
 let prefix: u8 = handshake.prefix;

 info!("registring tun {addr}/{prefix}");
 let device_name = &config.tun.name;
 let server_address = &config.quic.server_address.ip().to_string();
 let mtu = config.tun.mtu;
 let device = Arc::new(
 DeviceBuilder::new()
 .name(device_name)
 .ipv4(addr, prefix, None)
 .mtu(mtu)
 .build_async()?,
 );

 // добавляем маршруты, drop _guard их почистит
 let _guard = if config.tun.setup_routes {
 Some(setup_vpn_routes(server_address, device_name)?)
 } else {
 None
 };

 // задача на чтение из TUN и отправку по QUIC
 let mut device_recv_task = {
 let device = device.clone();
 let connection = connection.clone();
 tokio::spawn(async move {
 let mut buf = vec![0u8; READ_BUF_SIZE];
 loop {
 let n = device.recv(&mut buf).await?;
 connection.send_datagram(Bytes::copy_from_slice(&buf[..n]))?;
 }
 #[allow(unreachable_code)]
 Ok::<(), anyhow::Error>(())
 })
 };

 // задача на чтение по QUIC и отправку в TUN
 let mut connection_read_task = {
 let connection = connection.clone();
 if let Some(max_datagram_size) = connection.max_datagram_size() {
 info!("connection max_datagram_size = {max_datagram_size}");
 }
 let device = device.clone();
 tokio::spawn(async move {
 loop {
 let data = connection.read_datagram().await?;
 device.send(&data).await?;
 }
 #[allow(unreachable_code)]
 Ok::<(), anyhow::Error>(())
 })
 };

 let result = tokio::select! {
 res = &mut device_recv_task => res.unwrap_or_else(|e| Err(e.into())),
 res = &mut connection_read_task => res.unwrap_or_else(|e| Err(e.into())),
 };
 device_recv_task.abort();
 connection_read_task.abort();

 result
}
