IPAM
use std::collections::VecDeque;
use std::net::Ipv4Addr;
use std::sync::Mutex;

pub struct IpPool {
 pub subnet_base: Ipv4Addr,
 pub subnet_prefix: u8,
 available: Mutex<VecDeque<Ipv4Addr>>,
}

impl IpPool {
 pub fn new(subnet_base: Ipv4Addr, subnet_prefix: u8) -> Self {
 let base_u32 = u32::from(subnet_base);
 let host_bits = 32 - subnet_prefix as u32;
 let num_addrs = 1u32 << host_bits;

 // пропускаем 0, 1 и последний адрес
 let mut queue = VecDeque::new();
 for i in 2..(num_addrs - 1) {
 queue.push_back(Ipv4Addr::from(base_u32 + i));
 }

 IpPool {
 subnet_base,
 subnet_prefix,
 available: Mutex::new(queue),
 }
 }

 pub fn server_ip(&self) -> Ipv4Addr {
 let base_u32 = u32::from(self.subnet_base);
 return Ipv4Addr::from(base_u32 + 1);
 }

 pub fn allocate(&self) -> Option<Ipv4Addr> {
 self.available.lock().unwrap().pop_front()
 }

 pub fn release(&self, ip: Ipv4Addr) {
 self.available.lock().unwrap().push_back(ip);
 }
}
При создании QUIC endpoint подгружаем существующий или генерируем новый self signed сертификат
Server QUIC endpoint
use anyhow::Result;
use quinn::congestion::BbrConfig;
use quinn::{Endpoint, MtuDiscoveryConfig, ServerConfig, TransportConfig};
use rustls::pki_types::{CertificateDer, PrivateKeyDer, PrivatePkcs8KeyDer};
use tracing::info;

use std::fs;
use std::path::Path;
use std::sync::Arc;

use crate::config::QuicConfig;

pub fn make_server_endpoint(config: &QuicConfig) -> Result<Endpoint> {
 let server_config = configure_server(config)?;
 let endpoint = Endpoint::server(server_config, config.endpoint_address)?;
 Ok(endpoint)
}

fn configure_server(config: &QuicConfig) -> Result<ServerConfig> {
 let (cert_der, key_der) = load_or_generate_cert(config)?;
 let mut server_config = ServerConfig::with_single_cert(vec![cert_der.clone()], key_der)?;
 server_config.transport_config(Arc::new(build_transport_config(config)));

 Ok(server_config)
}

fn load_or_generate_cert(
 quic_config: &QuicConfig,
) -> Result<(CertificateDer<'static>, PrivateKeyDer<'static>)> {
 let cert_path = &quic_config.server_cert;
 let key_path = &quic_config.server_key;

 if Path::new(cert_path).exists() && Path::new(key_path).exists() {
 info!("loading existing cert + key");
 let cert_bytes = fs::read(cert_path)?;
 let key_bytes = fs::read(key_path)?;

 let cert = CertificateDer::from(cert_bytes);
 let key = PrivateKeyDer::Pkcs8(PrivatePkcs8KeyDer::from(key_bytes));

 Ok((cert, key))
 } else {
 info!("generating new cert + key");
 let subject_alt_names = vec![quic_config.server_name.clone().into()];
 let cert = rcgen::generate_simple_self_signed(subject_alt_names)?;

 let cert_der = cert.cert.der().to_vec();
 let key_der = cert.signing_key.serialize_der();

 fs::write(cert_path, &cert_der)?;
 fs::write(key_path, &key_der)?;

 let cert = CertificateDer::from(cert_der);
 let key = PrivateKeyDer::Pkcs8(PrivatePkcs8KeyDer::from(key_der));

 Ok((cert, key))
 }
}

fn build_transport_config(quic_config: &QuicConfig) -> TransportConfig {
 let mut transport = TransportConfig::default();

 transport.mtu_discovery_config(Some(MtuDiscoveryConfig::default()));
 transport.datagram_receive_buffer_size(Some(quic_config.receive_buffer_size_kb * 1024));
 transport.datagram_send_buffer_size(quic_config.send_buffer_size_kb * 1024);
 transport.max_concurrent_uni_streams(0u32.into());
 transport.max_concurrent_bidi_streams(10u32.into());
 transport.congestion_controller_factory(Arc::new(BbrConfig::default()));

 transport
}
Логика в целом похожа на клиентскую, тоже две задачи, одна – обработка новых QUIC подключений, другая – чтение из TUN и запись в QUIC
pub async fn run(&self) -> Result<()> {
 let subnet = format!(
 "{}/{}",
 self.ip_pool.subnet_base, self.ip_pool.subnet_prefix
 );

 // настраиваем nftables, drop _nat_guard почистит настройки
 let _nat_guard = if self.config.tun.setup_nat {
 Some(apply_vpn_nat(&subnet)?)
 } else {
 None
 };
 let device_worker = {
 let server = self.clone();
 self.task_tracker
 .spawn(async move { listen_device(server).await })
 };
 let connection_worker = {
 let server = self.clone();
 self.task_tracker
 .spawn(async move { accept_connections(server).await })
 };
 tokio::select! {
 r = device_worker => r.unwrap_or_else(|e| Err(e.into())),
 r = connection_worker => r.map_err(|e| anyhow::anyhow!(e)),
 }
}
При появлении нового соединения, запускаем отдельную задачу, выполняем handshake и в запускаем цикл отправки трафика connection -> device
async fn register(&self, connection: &Connection) -> Result<Session> {
 let ip = self
 .ip_pool
 .allocate()
 .ok_or_else(|| anyhow!("ip pool exhausted"))?;
 self.connections.insert(ip, connection.clone());
 // drop session приведет к освобождению адреса и удалению из connections
 let session = Session::new(ip, connection.clone(), self.clone());
 self.handshake(connection, ip).await?;
 Ok(session)
}

async fn handle_session(&self, session: Session) -> Result<()> {
 let mut consecutive_errors = 0;
 loop {
 let read = session.read().await?;
 if source_match(session.ip, &read) {
 match self.device.send(&read).await {
 Ok(_sent) => {
 consecutive_errors = 0;
 }
 Err(e) => {
 consecutive_errors += 1;
 if consecutive_errors > MAX_CONSECUTIVE_ERRORS {
 return Err(e.into());
 }
 sleep(Duration::from_millis(
 ERROR_BACKOFF_BASE_MS * consecutive_errors,
 ))
 .await;
 }
 }
 }
 }
}
